script:
frappe.ui.form.on("Sales Invoice", {
    refresh(frm) {
        add_support_billing_button(frm);
    },
    onload_post_render(frm) {
        add_support_billing_button(frm);
    }
});

function add_support_billing_button(frm) {
    if (frm.doc.docstatus !== 0) return;
    if (frm.support_billing_button_added) return;
    frm.page.add_inner_button(__("Support abrechnen"), function () {
        open_support_billing_dialog(frm);
    });
    frm.support_billing_button_added = true;
}

function format_currency(value) {
    return frappe.format(flt(value) || 0, { fieldtype: "Currency" });
}

function open_support_billing_dialog(frm) {
    const today = new Date();
    const first_day_last_month = frappe.datetime.obj_to_str(
        new Date(today.getFullYear(), today.getMonth() - 1, 1)
    );
    const last_day_last_month = frappe.datetime.obj_to_str(
        new Date(today.getFullYear(), today.getMonth(), 0)
    );

    const dialog = new frappe.ui.Dialog({
        title: __("Support abrechnen"),
        fields: [
            {
                fieldname: "customer",
                label: __("Kunde / Customer"),
                fieldtype: "Link",
                options: "Customer",
                reqd: 1,
                default: frm.doc.customer
            },
            {
                fieldname: "from_date",
                label: __("Von / From"),
                fieldtype: "Date",
                reqd: 1,
                default: first_day_last_month
            },
            {
                fieldname: "to_date",
                label: __("Bis / To"),
                fieldtype: "Date",
                reqd: 1,
                default: last_day_last_month
            },
            {
                fieldname: "project",
                label: __("Projekt / Project"),
                fieldtype: "Link",
                options: "Project",
                get_query: function () {
                    return { filters: { customer: dialog.get_value("customer") } };
                },
                onchange: function () {
                    // Disable service quota when a project is selected
                    if (dialog.get_value("project")) {
                        dialog.set_value("take_service_quota", 0);
                    } else {
                        dialog.set_value("take_service_quota", 1);
                    }
                }
            },
            {
                fieldname: "take_service_quota",
                label: __("Dienstleistungskontingent berücksichtigen"),
                fieldtype: "Check",
                default: 1
            }
        ],
        primary_action_label: __("Suchen"),
        primary_action: function (values) {
            frappe.call({
                method: "custom_helpdesk.python_scripts.billing.support_invoice.get_support_invoice_candidates",
                args: {
                    customer: values.customer,
                    from_date: values.from_date,
                    to_date: values.to_date,
                    project: values.project || "",
                    take_service_quota: values.take_service_quota
                },
                freeze: true,
                freeze_message: __("Passende Zeiterfassungen werden gesucht..."),
                callback(r) {
                    if (!r.message) return;
                    dialog.hide();
                    open_support_selection_dialog(frm, values, r.message);
                }
            });
        }
    });

    dialog.show();
}

function open_support_selection_dialog(frm, filters, data) {
    const rows = data.rows || [];
    const customer_rabatt = data.customer_rabatt || 0;
    if (!rows.length) {
        frappe.msgprint({
            title: __("Keine Daten gefunden"),
            indicator: "orange",
            message: __("Für die gewählten Kriterien wurden keine abrechenbaren Zeitpositionen gefunden.")
        });
        return;
    }

    let table_html = `
        <div style="max-height: 420px; overflow-y: auto;">
            <table class="table table-bordered table-sm">
                <thead>
                    <tr>
                        <th style="width: 40px;">
                            <input type="checkbox" class="select-all-support-rows" checked>
                        </th>
                        <th>Timesheet</th>
                        <th>Datum</th>
                        <th>Projekt</th>
                        <th>Preiskategorie</th>
                        <th>Stunden</th>
                        <th>Stundensatz</th>
                        <th>Betrag</th>
                        <th>Rabatt (%)</th>
                    </tr>
                </thead>
                <tbody>
    `;

    rows.forEach((row, index) => {
        table_html += `
            <tr data-base-amount="${flt(row.amount || 0, 2)}">
                <td><input type="checkbox" class="support-row-checkbox" data-index="${index}" checked></td>
                <td>${frappe.utils.escape_html(row.timesheet || "")}</td>
                <td>${frappe.utils.escape_html(row.date || "")}</td>
                <td>${frappe.utils.escape_html(row.project || "")}</td>
                <td>${frappe.utils.escape_html(row.category_name || "")}</td>
                <td>${flt(row.hours || 0, 2)}</td>
                <td>${format_currency(row.rate || 0)}</td>
                <td class="betrag-cell">${format_currency(row.amount || 0)}</td>
                <td><input type="number" min="0" max="100" class="rabatt-input" style="width:60px;text-align:right;" value="${customer_rabatt}"></td>
            </tr>
        `;
    });

    table_html += `</tbody></table></div>`;

    const selection_dialog = new frappe.ui.Dialog({
        title: __("Zeiterfassungen auswählen"),
        fields: [
            { fieldname: "selection_html", fieldtype: "HTML", options: table_html }
        ],
        primary_action_label: __("Importieren"),
        primary_action: function () {
            const selected_rows = [];
            selection_dialog.$wrapper.find(".support-row-checkbox:checked").each(function () {
                const idx = Number($(this).attr("data-index"));
                const rabatt = parseInt($(this).closest("tr").find(".rabatt-input").val()) || 0;
                selected_rows.push(Object.assign({}, rows[idx], { rabatt: rabatt }));
            });

            if (!selected_rows.length) {
                frappe.msgprint({
                    title: __("Keine Auswahl"),
                    indicator: "orange",
                    message: __("Bitte mindestens eine Zeitposition auswählen.")
                });
                return;
            }

            frappe.call({
                method: "custom_helpdesk.python_scripts.billing.support_invoice.import_support_invoice_candidates",
                args: {
                    customer: filters.customer,
                    from_date: filters.from_date,
                    to_date: filters.to_date,
                    project: filters.project || "",
                    take_service_quota: filters.take_service_quota,
                    selected_rows: selected_rows
                },
                freeze: true,
                freeze_message: __("Positionen werden importiert..."),
                callback(r) {
                    if (!r.message) return;
                    apply_support_import_to_invoice(frm, r.message);
                    selection_dialog.hide();
                    frappe.show_alert({
                        message: __("Supportpositionen wurden in die Ausgangsrechnung übernommen."),
                        indicator: "green"
                    });
                }
            });
        }
    });

    selection_dialog.show();

    selection_dialog.$wrapper.find(".select-all-support-rows").on("change", function () {
        selection_dialog.$wrapper.find(".support-row-checkbox").prop("checked", $(this).is(":checked"));
    });

    selection_dialog.$wrapper.find(".rabatt-input").on("input", function () {
        const $tr = $(this).closest("tr");
        const base = parseFloat($tr.attr("data-base-amount")) || 0;
        const pct = parseInt($(this).val()) || 0;
        const discounted = base * (1 - pct / 100);
        $tr.find(".betrag-cell").text(format_currency(discounted));
    });
}

function apply_support_import_to_invoice(frm, data) {
    if (data.customer) frm.set_value("customer", data.customer);
    if (data.project) frm.set_value("project", data.project);

    if (data.timesheet_names && data.timesheet_names.length) {
        frm.set_value("custom_support_timesheet_refs", JSON.stringify(data.timesheet_names));
    }

    frm.clear_table("items");
    (data.items || []).forEach(row => {
        const item = frm.add_child("items");
        item.item_code = row.item_code;
        item.item_name = row.item_name || row.item_code;
        item.description = row.description || row.item_code;
        item.qty = row.qty;
        item.rate = row.rate;
        item.amount = row.amount;
        if (data.project) item.project = data.project;
    });

    frm.refresh_field("items");
}
